import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { PackagePlus, LayoutDashboard, ClipboardList, Store, PlusCircle, ArrowLeft } from 'lucide-react';
import { generarNombreImagen, DICCIONARIO_PRODUCTOS, URL_CARPETA_IMAGENES } from '../utils/helpers';
import CargaMasiva from './CargaMasiva';
import VistaPedidosVendedor from './VistaPedidosVendedor';
import { useAuth } from '../context/AuthContext';

const DashboardVendedor = () => {
  const { user } = useAuth();
  const [locales, setLocales] = useState([]);
  const [localActivo, setLocalActivo] = useState(null);
  const [mostrarFormLocal, setMostrarFormLocal] = useState(false);
  const [vista, setVista] = useState('pedidos');
  const [loading, setLoading] = useState(true);

  // Estados para nuevo Local
  const [nuevoLocal, setNuevoLocal] = useState({ nombre: '', direccion: '', telefono: '' });

  // Estados para nuevo Producto
  const [sugerencias, setSugerencias] = useState([]);
  const [form, setForm] = useState({ 
    categoria: 'Almacén', tipo: '', marca: '', contenido: '', 
    precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: ''
  });

  useEffect(() => {
    fetchLocales();
  }, []);

  const fetchLocales = async () => {
    try {
      const res = await axios.get(`${process.env.REACT_APP_API_URL}/api/locales/vendedor/${user.id || user._id}`);
      setLocales(res.data);
      // Si solo tiene uno, lo activamos por defecto
      if (res.data.length === 1) setLocalActivo(res.data[0]);
    } catch (err) {
      console.error("Error al traer locales", err);
    } finally {
      setLoading(false);
    }
  };

  const crearLocal = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(`${process.env.REACT_APP_API_URL}/api/locales`, {
        ...nuevoLocal,
        vendedor: user.id || user._id
      });
      setLocales([...locales, res.data]);
      setLocalActivo(res.data);
      setMostrarFormLocal(false);
      setNuevoLocal({ nombre: '', direccion: '', telefono: '' });
    } catch (err) {
      alert("Error al crear el local");
    }
  };

  const handleTipoChange = (val) => {
    setForm({ ...form, tipo: val });
    if (val.length > 1) {
      const filtradas = DICCIONARIO_PRODUCTOS[form.categoria]?.filter(i => 
        i.toLowerCase().includes(val.toLowerCase())
      ) || [];
      setSugerencias(filtradas);
    } else { setSugerencias([]); }
  };

  const publicarIndividual = async (e) => {
    e.preventDefault();
    const publicId = generarNombreImagen(form.tipo, form.marca, form.contenido);
    const oferta = {
      producto: `${form.tipo} ${form.marca} ${form.contenido}`,
      categoria: form.categoria,
      precioNuevo: Number(form.precioNuevo),
      precioViejo: Number(form.precioViejo || form.precioNuevo),
      stock: Number(form.stock),
      publicId: publicId,
      local: localActivo?._id || localActivo?.id,
      fechaVencimiento: form.fechaVencimiento
    };

    try {
      await axios.post(`${process.env.REACT_APP_API_URL}/api/ofertas`, oferta);
      alert("✅ Producto publicado");
      setForm({ ...form, tipo: '', marca: '', contenido: '', precioNuevo: '', precioViejo: '', stock: '' });
    } catch (err) { alert("Error al guardar"); }
  };

  // --- VISTA: SELECCIÓN DE LOCAL ---
  if (!localActivo && !loading) {
    return (
      <div style={containerStyle}>
        <div style={headerStyle}>
          <h2 style={{margin:0}}>Mis Locales</h2>
          <button onClick={() => setMostrarFormLocal(!mostrarFormLocal)} style={btnCrearLocal}>
            {mostrarFormLocal ? 'Cancelar' : <><PlusCircle size={18}/> Nuevo Local</>}
          </button>
        </div>

        {mostrarFormLocal ? (
          <form onSubmit={crearLocal} style={formStyle}>
            <h3>Registrar Nuevo Local</h3>
            <input style={inputStyle} placeholder="Nombre del Local" value={nuevoLocal.nombre} onChange={e => setNuevoLocal({...nuevoLocal, nombre: e.target.value})} required />
            <input style={inputStyle} placeholder="Dirección" value={nuevoLocal.direccion} onChange={e => setNuevoLocal({...nuevoLocal, direccion: e.target.value})} required />
            <input style={inputStyle} placeholder="Teléfono" value={nuevoLocal.telefono} onChange={e => setNuevoLocal({...nuevoLocal, telefono: e.target.value})} />
            <button type="submit" style={btnSubmit}>Guardar Local</button>
          </form>
        ) : (
          <div style={gridLocales}>
            {locales.map(l => (
              <div key={l._id} style={cardLocal} onClick={() => setLocalActivo(l)}>
                <Store size={40} color="#e67e22" />
                <h3 style={{margin: '10px 0 5px 0'}}>{l.nombre}</h3>
                <p style={{fontSize: '0.8rem', color: '#64748b'}}>{l.direccion}</p>
              </div>
            ))}
            {locales.length === 0 && <p>No tienes locales registrados aún.</p>}
          </div>
        )}
      </div>
    );
  }

  // --- VISTA: DASHBOARD DEL LOCAL SELECCIONADO ---
  return (
    <div style={containerStyle}>
      <header style={headerStyle}>
        <div style={{display: 'flex', alignItems: 'center', gap: '15px'}}>
          <button onClick={() => setLocalActivo(null)} style={btnBack}><ArrowLeft size={20}/></button>
          <div>
            <h2 style={{ margin: 0 }}>{localActivo?.nombre}</h2>
            <p style={{ margin: 0, fontSize: '0.8rem', color: '#64748b' }}>Gestión de local</p>
          </div>
        </div>
        <div style={tabContainer}>
          <button onClick={() => setVista('pedidos')} style={vista === 'pedidos' ? tabActive : tabInactive}>
            <ClipboardList size={18} /> Pedidos
          </button>
          <button onClick={() => setVista('productos')} style={vista === 'productos' ? tabActive : tabInactive}>
            <PackagePlus size={18} /> Productos
          </button>
        </div>
      </header>

      {vista === 'pedidos' ? (
        <VistaPedidosVendedor localId={localActivo?._id || localActivo?.id} />
      ) : (
        <section>
          <CargaMasiva localId={localActivo?._id || localActivo?.id} onComplete={() => {}} />
          <form onSubmit={publicarIndividual} style={{...formStyle, marginTop: '20px'}}>
            <h3 style={formTitle}>Nuevo Producto Individual</h3>
            <label style={labelStyle}>Categoría</label>
            <select style={inputStyle} value={form.categoria} onChange={e => setForm({...form, categoria: e.target.value})}>
              {Object.keys(DICCIONARIO_PRODUCTOS).map(c => <option key={c} value={c}>{c}</option>)}
            </select>
            <input style={inputStyle} placeholder="Tipo de Producto" value={form.tipo} onChange={e => handleTipoChange(e.target.value)} required />
            <div style={{display:'flex', gap:'10px'}}>
              <input style={inputStyle} placeholder="Marca" value={form.marca} onChange={e => setForm({...form, marca: e.target.value})} required />
              <input style={inputStyle} placeholder="Contenido" value={form.contenido} onChange={e => setForm({...form, contenido: e.target.value})} required />
            </div>
            <div style={{display:'flex', gap:'10px'}}>
              <input type="number" style={inputStyle} placeholder="Precio $" value={form.precioNuevo} onChange={e => setForm({...form, precioNuevo: e.target.value})} required />
              <input type="number" style={inputStyle} placeholder="Stock" value={form.stock} onChange={e => setForm({...form, stock: e.target.value})} required />
              <input type="date" style={inputStyle} value={form.fechaVencimiento} onChange={e => setForm({...form, fechaVencimiento: e.target.value})} required />
            </div>
            <button type="submit" style={btnSubmit}>Publicar Oferta</button>
          </form>
        </section>
      )}
    </div>
  );
};

// --- ESTILOS ADICIONALES ---
const containerStyle = { padding: '20px', maxWidth: '900px', margin: '0 auto', fontFamily: 'sans-serif' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', background: 'white', padding: '20px', borderRadius: '16px', border: '1px solid #e2e8f0' };
const gridLocales = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px', marginTop: '20px' };
const cardLocal = { background: 'white', padding: '30px', borderRadius: '20px', border: '1px solid #e2e8f0', textAlign: 'center', cursor: 'pointer', transition: '0.2s', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const btnCrearLocal = { background: '#e67e22', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };
const btnBack = { background: '#f1f5f9', border: 'none', padding: '10px', borderRadius: '10px', cursor: 'pointer', color: '#475569' };
const formStyle = { background: 'white', padding: '25px', borderRadius: '20px', border: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column', gap: '15px' };
const inputStyle = { width: '100%', padding: '12px', borderRadius: '10px', border: '1px solid #e2e8f0', outline: 'none' };
const btnSubmit = { background: '#1e293b', color: 'white', padding: '14px', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer' };
const tabContainer = { display: 'flex', background: '#f1f5f9', padding: '5px', borderRadius: '12px', gap: '5px' };
const tabActive = { display: 'flex', alignItems: 'center', gap: '8px', padding: '8px 16px', border: 'none', borderRadius: '8px', background: 'white', color: '#1e293b', fontWeight: 'bold', cursor: 'pointer' };
const tabInactive = { display: 'flex', alignItems: 'center', gap: '8px', padding: '8px 16px', border: 'none', borderRadius: '8px', background: 'transparent', color: '#64748b', cursor: 'pointer' };
const labelStyle = { fontSize: '0.65rem', fontWeight: '800', color: '#94a3b8', textTransform: 'uppercase' };
const formTitle = { fontSize: '1rem', margin: '0', color: '#1e293b' };

export default DashboardVendedor;
